package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testIsCommentMarkerSet_whenCommentMarkerIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // By default, commentMarker is null in DEFAULT
        // Use reflection to ensure commentMarker is null
        Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);
        commentMarkerField.set(format, null);

        assertFalse(format.isCommentMarkerSet());
    }

    @Test
    public void testIsCommentMarkerSet_whenCommentMarkerIsNonNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Set commentMarker to a non-null Character using reflection
        Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);
        commentMarkerField.set(format, '#');

        assertTrue(format.isCommentMarkerSet());
    }
}
